function scoreCountries(a) {
    const s = { usa: 40, europe: 45, china: 40, russia: 35 };
    const b = a.budget ?? 1;
    if (b >= 3) {
        s.usa += 30;
        s.europe += 15;
    }
    if (b === 2) {
        s.usa += 15;
        s.europe += 25;
        s.china += 10;
    }
    if (b === 1) {
        s.europe += 20;
        s.china += 22;
        s.usa += 5;
    }
    // Квалификация StudyEurope: без бюджета на проживание 1000–1300 €/мес Европа честно проседает
    if (b === 0) {
        s.china += 35;
        s.europe -= 8;
        s.russia += 15;
        s.usa += 5;
    }
    if (a.priority === "prestige")
        s.usa += 15;
    if (a.priority === "career") {
        s.europe += 15;
        s.china += 5;
    }
    if (a.priority === "budget_care") {
        s.china += 18;
        s.europe += 5;
    }
    if (a.priority === "safety") {
        s.europe += 10;
        s.china += 5;
    }
    const eng = a.eng ?? 1;
    if (eng >= 2) {
        s.usa += 10;
        s.europe += 10;
    }
    else {
        s.china += 10;
        s.russia += 10;
    }
    if ((a.activ ?? 0) >= 2)
        s.usa += 10;
    // Второй язык — реальный актив заявки: китайский открывает Китай, немецкий/французский — Европу
    if (a.lang2 === "china")
        s.china += 12;
    if (a.lang2 === "europe")
        s.europe += 10;
    Object.keys(s).forEach(k => { s[k] = Math.max(20, Math.min(96, s[k])); });
    return s;
}
