// Детерминированная сортировка стран под профиль (ИИ не участвует — правило журнала §2.2).
// База 50, бонусы за язык/бюджет/климат/направление; только порядок, ученику проценты не показываем.
function euScore(id, anketa) {
    let s = 50;
    const b = anketa.budget ?? 1, geo = anketa.geo, f = anketa.field;
    if (anketa.lang2 === "europe")
        s += ({ de: 12, at: 10, fr: 10, be: 6 }[id] || 0); // немецкий/французский из анкеты
    if (b === 0)
        s += ({ de: 12, at: 10, es: 8, it: 8, fr: 4 }[id] || 0); // дешёвое гос. обучение
    if (b >= 2)
        s += ({ nl: 6, ie: 6, dk: 4 }[id] || 0); // бюджет позволяет дорогие системы
    if (geo === "warm")
        s += ({ es: 10, it: 8, fr: 5 }[id] || 0);
    if (geo === "city")
        s += ({ nl: 5, de: 5, fr: 5, es: 3 }[id] || 0);
    if (geo === "campus")
        s += ({ ie: 6, nl: 4, se: 4, dk: 4 }[id] || 0);
    if (f === "it")
        s += ({ nl: 6, de: 6, se: 5, dk: 5 }[id] || 0);
    if (f === "biz")
        s += ({ ie: 5, nl: 4, es: 4, fr: 4 }[id] || 0);
    if (f === "med")
        s += ({ it: 5, nl: 3, dk: 3 }[id] || 0);
    if (f === "art")
        s += ({ fr: 6, it: 5, at: 4 }[id] || 0);
    return s;
}
const euRanked = (anketa) => [...EU_COUNTRIES].sort((a, b2) => euScore(b2.id, anketa) - euScore(a.id, anketa));
