// «Кем учиться» в конкретном вузе: направление под специализацию ученика (или первое подходящее профилю вуза)
function progFor(u, field) {
    const p = UNI_PROGRAMS[u.name];
    if (!p)
        return null;
    if (field && p[field])
        return p[field];
    for (const f of (u.fit || []))
        if (p[f])
            return p[f];
    return null;
}
// «Кем работать»: профессии из карты талантов типа, отобранные под специализацию (словарная классификация)
const FIELD_PROF_WORDS = {
    it: ["it", "программист", "разработчик", "данн", "data", "кибер", "техническ", "инженер", "веб-", "r&d", "стартап"],
    med: ["врач", "хирург", "медик", "медицин", "психолог", "биолог", "косметолог", "нутрициолог", "здоров"],
    biz: ["директор", "менеджер", "управлен", "предприним", "бизнес", "лидер", "финанс", "бухгалтер", "маркетолог", "таргетолог", "smm", "продаж", "юрист", "аудитор", "логист", "банкир", "экономист", "риск-", "консалт", "коуч", "hr", "нетворкер", "продакт", "судья", "прокурор"],
    art: ["дизайнер", "режисс", "художник", "иллюстратор", "аниматор", "писатель", "сценарист", "журналист", "копирайтер", "фотограф", "видеограф", "музыкант", "композитор", "актёр", "актер", "певец", "ведущий", "блогер", "контент", "стилист", "красот", "арт-", "гейм-", "креатив", "архитектор", "шоу", "оратор", "спикер", "продюсер"],
};
const FIELD_FALLBACK_PROFS = {
    it: ["Разработчик", "Аналитик данных", "Продакт-менеджер"],
    med: ["Врач-специалист", "Исследователь в биомедицине", "Клинический психолог"],
    biz: ["Менеджер проектов", "Финансовый аналитик", "Предприниматель"],
    art: ["Дизайнер", "Продюсер контента", "Арт-директор"],
};
function profsForField(profFit, field) {
    const list = profFit || [];
    if (!field)
        return list.slice(0, 3);
    const words = FIELD_PROF_WORDS[field] || [];
    const out = list.filter(p => { const l = p.toLowerCase(); return words.some(w => l.includes(w)); }).slice(0, 3);
    if (out.length < 2)
        for (const f of (FIELD_FALLBACK_PROFS[field] || [])) {
            if (out.length >= 3)
                break;
            if (!out.includes(f))
                out.push(f);
        }
    return out;
}
