async function askClaude(messages, system, tools) {
    const res = await fetch(AI_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ model: "claude-sonnet-4-6", max_tokens: tools ? 2000 : 1000, system, messages, ...(tools ? { tools } : {}) }),
    });
    // Диагностика сбоев: статус и текст ошибки шлюза — в консоль (на экран ученику технику не выносим)
    const raw = await res.text();
    let data = {};
    try {
        data = JSON.parse(raw);
    }
    catch (e) { /* не-JSON от шлюза — обработаем ниже */ }
    if (!res.ok || data.error) {
        const why = (data.error && (data.error.message || data.error.type)) || raw.slice(0, 200) || "пустой ответ";
        console.warn("ИИ-шлюз ответил ошибкой:", res.status, why);
        throw new Error("AI " + res.status + ": " + why);
    }
    return (data.content || []).filter(b => b.type === "text").map(b => b.text).join("\n");
}
const parseJson = (raw) => {
    const clean = raw.replace(/```json/gi, "").replace(/```/g, "").trim();
    return JSON.parse(clean.slice(clean.indexOf("{"), clean.lastIndexOf("}") + 1));
};
// Устойчивый парсер: если JSON обрезан лимитом токенов — достраивает оборванные скобки
const parseJsonLoose = (raw) => {
    let s = (raw || "").replace(/```json/gi, "").replace(/```/g, "").trim();
    const start = s.indexOf("{");
    if (start < 0)
        throw new Error("в ответе нет JSON");
    s = s.slice(start);
    try {
        return JSON.parse(s.slice(0, s.lastIndexOf("}") + 1));
    }
    catch (e) { }
    const closers = (str) => {
        let inStr = false, esc = false;
        const stack = [];
        for (const ch of str) {
            if (esc) {
                esc = false;
                continue;
            }
            if (ch === "\\") {
                esc = true;
                continue;
            }
            if (ch === '"') {
                inStr = !inStr;
                continue;
            }
            if (inStr)
                continue;
            if (ch === "{" || ch === "[")
                stack.push(ch);
            else if (ch === "}" || ch === "]")
                stack.pop();
        }
        let out = inStr ? '"' : "";
        while (stack.length)
            out += stack.pop() === "{" ? "}" : "]";
        return out;
    };
    for (let i = s.length; i > 2 && s.length - i <= 500; i--) {
        const ch = s[i - 1];
        if (i !== s.length && ch !== '"' && ch !== "}" && ch !== "]")
            continue;
        const cand = s.slice(0, i).replace(/,\s*$/, "");
        try {
            return JSON.parse(cand + closers(cand));
        }
        catch (e) { }
    }
    throw new Error("JSON не восстановился");
};
